package pl.rezerwacjasal.rezerwacjasal.controller; import java.time.LocalDateTime; import java.util.List; import org.springframework.format.annotation.DateTimeFormat; import org.springframework.web.bind.annotation.*; import lombok.RequiredArgsConstructor; import pl.rezerwacjasal.rezerwacjasal.model.RoomReservation; import pl.rezerwacjasal.rezerwacjasal.service.RoomReservationService; @RestController @RequiredArgsConstructor @RequestMapping("/api/rooms") public class RoomController { private final RoomReservationService service; @GetMapping("/{roomId}/schedule") public List<RoomReservation> schedule(@PathVariable Long roomId) { return service.getSchedule(roomId); } @PostMapping("/{roomId}/reservations") public String reserve(@PathVariable Long roomId, @RequestParam @DateTimeFormat(iso=DateTimeFormat.ISO.DATE_TIME) LocalDateTime startTime, @RequestParam @DateTimeFormat(iso=DateTimeFormat.ISO.DATE_TIME) LocalDateTime endTime) { RoomReservation r=service.createReservation(roomId,startTime,endTime); return "Reservation created id: "+r.getId()+", price: "+r.getTotalPrice(); } }
